import React, { useState, useEffect } from 'react';
import { withRouter } from 'react-router-dom';

import BlogPostStore from '../stores/BlogPostStore';

import ReactMarkdown from 'react-markdown';

function BlogPost(props) {
  const [post, setPost] = useState(null);
  const getLatest = () => BlogPostStore.getLatest().then(setPost);
  const getPost = title => BlogPostStore.getPostByTitle(title).then(p => p && setPost(p));

  useEffect(() => {
    if (props.latest) getLatest();
    else if (props.match && props.match.params && props.match.params.title)
      getPost(props.match.params.title);
  });

  return (
    <div className="blog-post">
      <ReactMarkdown source={props.source || post} />
    </div>
  );
}

export default withRouter(BlogPost);



